from crewai_tools import BaseTool
import requests

class TicketCreationTool(BaseTool):
    name: str = "Create Support Ticket"
    description: str = "Creates Zendesk ticket for customer issue"

    def _run(self, customer_email: str, issue_summary: str, priority: str = 'normal') -> str:
        payload = {
            'ticket': {
                'subject': f'Support Request: {issue_summary[:50]}',
                'comment': {'body': issue_summary},
                'requester': {'email': customer_email},
                'priority': priority
            }
        }
        response = requests.post(
            'https://yourcompany.zendesk.com/api/v2/tickets.json',
            json=payload,
            headers={'Authorization': 'Basic YOUR_ZENDESK_TOKEN'}
        )
        ticket_id = response.json()['ticket']['id']
        return f'Ticket #{ticket_id} created successfully'

