from vex_sdk import VexClient
from crewai import Task

vex = VexClient(api_key='your-vex-api-key')

def vex_task_callback(task_output: str, task_context: dict) -> bool:
    # Verify customer support specific requirements
    checks = [
        {
            'type': 'response_accuracy',
            'prompt': f"Is this output accurate for query: {task_context['customer_query']}?",
            'threshold': 0.9
        },
        {
            'type': 'pii_filter',
            'rules': ['PHONE_NUMBER', 'EMAIL', 'SSN'],
            'action': 'redact'
        },
        {
            'type': 'tone_consistency',
            'target_tone': 'professional empathetic',
            'threshold': 0.8
        },
        {
            'type': 'policy_compliance',
            'policies': ['no_personal_opinions', 'no_price_guarantees']
        }
    ]

    result = vex.verify(
        content=task_output,
        checks=checks,
        context=task_context,
        risk_profile='high'
    )
    return result['approved']

# Apply to research agent task
triage_task = Task(
    description='Analyze: {customer_query}',
    agent=triage_agent,
    output_callback=lambda x: vex_task_callback(x, {'customer_query': customer_query})
)

def final_response_guardrail(response: str, context: dict) -> dict:
    escalation_checks = [
        {
            'type': 'keyword_trigger',
            'keywords': ['legal action', 'lawsuit', 'attorney', 'refund all purchases'],
            'severity': 'critical'
        },
        {
            'type': 'sentiment',
            'min_score': -0.8,
            'labels': ['anger', 'threat']
        },
        {
            'type': 'policy_violation',
            'policy': 'escalation_handling',
            'rules': [
                'Cannot promise executive callback',
                'Must route legal threats to compliance'
            ]
        }
    ]

    result = vex.verify(
        content=response,
        checks=escalation_checks,
        context=context,
        risk_profile='high'
    )

    if result['approved']:
        return {'status': 'send_to_customer', 'content': result['content']}
    else:
        return {
            'status': 'escalate',
            'reason': result['failures'],
            'escalation_type': 'human_compliance',
            'ticket_id': context.get('ticket_id')
        }

